121	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
122	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
123	    let required = match rbtdrm_required_colophons(fixture) {
124	        Some(r) => r,
125	        None => {
126	            return Err(format!(
127	                "rbtd: unknown fixture '{}' — not registered in manifest",
128	                fixture
129	            ));
130	        }
131	    };
132	    for colophon in required {
133	        let found = manifest.split_whitespace().any(|token| token == *colophon);
134	        if !found {
135	            return Err(format!(
136	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
137	                colophon, fixture
138	            ));
139	        }
140	    }
141	    Ok(())
142	}
